447	        -- rmax = amax-bmin
448	        --     If bFmt.S = 0: rmax = (2**aFmt.I - 2**-aFmt.F) - 0
449	        --     If bFmt.S = 1: rmax = (2**aFmt.I - 2**-aFmt.F) + 2**bFmt.I
450	        -- If bFmt.S = 0, then rmaxFmt = aFmt.
451	        -- If bFmt.S = 1 and aFmt.I >= bFmt.I, then we get 1 bit of growth if:
452	        --                -2**-aFmt.F + 2**bFmt.I >= 0
453	        --                              2**bFmt.I >= 2**-aFmt.F
454	        -- If bFmt.S = 1 and bFmt.I >= aFmt.I, then we get 1 bit of growth if:
455	        --                -2**-aFmt.F + 2**aFmt.I >= 0
456	        --                              2**aFmt.I >= 2**-aFmt.F
457	        if b_fmt.S = 0 then
